import{o as n,c as s,b as a}from"./app.3132835d.js";const t='{"title":"浏览器中的的Event Loop","description":"JavaScript 语言的一大特点就是单线程。单线程就意味着，所有任务需要排队，前一个任务结束，才会执行后一个任务。如果前一个任务耗时很长，后一个任务就不得不一直等着。为了协调事件（event），用户交互（user interaction），脚本（script），渲染（rendering），网络（networking）等，用户代理（user agent）必须使用事件循环。","frontmatter":{"title":"浏览器中的的Event Loop","date":"2020-04-09","tags":["Javascript"],"description":"JavaScript 语言的一大特点就是单线程。单线程就意味着，所有任务需要排队，前一个任务结束，才会执行后一个任务。如果前一个任务耗时很长，后一个任务就不得不一直等着。为了协调事件（event），用户交互（user interaction），脚本（script），渲染（rendering），网络（networking）等，用户代理（user agent）必须使用事件循环。"},"headers":[{"level":2,"title":"单线程的Javascript","slug":"单线程的javascript"},{"level":2,"title":"微任务和宏任务","slug":"微任务和宏任务"},{"level":2,"title":"关于事件循环","slug":"关于事件循环"},{"level":2,"title":"为何需要事件循环","slug":"为何需要事件循环"},{"level":2,"title":"举例分析","slug":"举例分析"},{"level":2,"title":"进阶之async/await","slug":"进阶之async-await"},{"level":3,"title":"先稍微讲一下async/await。","slug":"先稍微讲一下async-await。"},{"level":3,"title":"开始分析","slug":"开始分析"},{"level":2,"title":"关于Event Loop值的细读的文章","slug":"关于event-loop值的细读的文章"}],"relativePath":"blog/jsEventLoop.md","lastUpdated":1620464054193}',p={},o=a('',24);p.render=function(a,t,p,e,c,u){return n(),s("div",null,[o])};export default p;export{t as __pageData};
